import{_ as a,o,c as r,a3 as i}from"./chunks/framework.DrNtA5hy.js";const m=JSON.parse('{"title":"Política de Privacidade","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/privacy-policy.md","filePath":"pt-BR/privacy-policy.md"}'),t={name:"pt-BR/privacy-policy.md"};function s(d,e,n,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="politica-de-privacidade" tabindex="-1">Política de Privacidade <a class="header-anchor" href="#politica-de-privacidade" aria-label="Permalink to &quot;Política de Privacidade&quot;">​</a></h1><p><strong>Última atualização:</strong> 2 de março de 2026</p><h2 id="visao-geral" tabindex="-1">Visão Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visão Geral&quot;">​</a></h2><p>Specialist Agent é uma ferramenta CLI open-source e plugin para editores de código com IA. Esta Política de Privacidade explica como os dados são tratados pela ferramenta e por este site de documentação.</p><h2 id="a-ferramenta-cli" tabindex="-1">A Ferramenta CLI <a class="header-anchor" href="#a-ferramenta-cli" aria-label="Permalink to &quot;A Ferramenta CLI&quot;">​</a></h2><p>O Specialist Agent opera <strong>inteiramente na sua máquina local</strong>. A ferramenta:</p><ul><li><strong>Não</strong> coleta, transmite ou armazena dados pessoais</li><li><strong>Não</strong> inclui telemetria ou rastreamento de uso</li><li><strong>Não</strong> se comunica com servidores externos por conta própria</li><li>Processa todos os arquivos e código <strong>localmente</strong> no seu ambiente de desenvolvimento</li></ul><h3 id="comunicacao-com-provedores-de-ia" tabindex="-1">Comunicação com Provedores de IA <a class="header-anchor" href="#comunicacao-com-provedores-de-ia" aria-label="Permalink to &quot;Comunicação com Provedores de IA&quot;">​</a></h3><p>Quando você usa o Specialist Agent através de um editor com IA (Claude Code, Cursor, VS Code, etc.), seus prompts e contexto de código são enviados ao <strong>provedor de IA</strong> (ex: Anthropic, OpenAI) pelo editor — não pelo Specialist Agent. Essas comunicações são regidas pela política de privacidade do respectivo provedor:</p><ul><li><a href="https://www.anthropic.com/privacy" target="_blank" rel="noreferrer">Política de Privacidade da Anthropic</a></li><li><a href="https://openai.com/privacy" target="_blank" rel="noreferrer">Política de Privacidade da OpenAI</a></li></ul><h2 id="site-de-documentacao" tabindex="-1">Site de Documentação <a class="header-anchor" href="#site-de-documentacao" aria-label="Permalink to &quot;Site de Documentação&quot;">​</a></h2><p>Este site de documentação (<code>specialistagent.com.br</code>) pode utilizar serviços de analytics para entender como os visitantes interagem com o conteúdo. Os dados coletados são anônimos e podem incluir:</p><ul><li>Páginas visitadas e padrões de navegação</li><li>Localização geográfica aproximada (nível de país/região)</li><li>Tipo de dispositivo, navegador e sistema operacional</li><li>Fonte de referência</li><li>Tempo gasto nas páginas</li></ul><p>Esses dados são usados exclusivamente para melhorar a documentação. Nenhuma informação pessoal identificável é coletada através do analytics.</p><h3 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h3><p>Este site pode utilizar cookies para:</p><ul><li><strong>Analytics</strong>: Para medir o tráfego e padrões de uso do site</li><li><strong>Preferências</strong>: Para lembrar sua seleção de idioma (Inglês / Português)</li></ul><p>Você pode desativar cookies através das configurações do seu navegador a qualquer momento.</p><h3 id="hospedagem" tabindex="-1">Hospedagem <a class="header-anchor" href="#hospedagem" aria-label="Permalink to &quot;Hospedagem&quot;">​</a></h3><p>Este site é hospedado no <a href="https://docs.github.com/en/pages/getting-started-with-github-pages/about-github-pages#data-collection" target="_blank" rel="noreferrer">GitHub Pages</a>. O GitHub pode coletar dados técnicos como endereços IP para fins de segurança e operação. Consulte a <a href="https://docs.github.com/en/site-policy/privacy-policies/github-general-privacy-statement" target="_blank" rel="noreferrer">Declaração de Privacidade do GitHub</a> para mais detalhes.</p><h2 id="servicos-de-terceiros" tabindex="-1">Serviços de Terceiros <a class="header-anchor" href="#servicos-de-terceiros" aria-label="Permalink to &quot;Serviços de Terceiros&quot;">​</a></h2><p>O Specialist Agent é distribuído via <a href="https://www.npmjs.com/" target="_blank" rel="noreferrer">npm</a>. Quando você instala o pacote usando <code>npm install</code> ou <code>npx</code>, o npm pode coletar dados de uso conforme descrito em sua <a href="https://docs.npmjs.com/policies/privacy" target="_blank" rel="noreferrer">política de privacidade</a>.</p><h2 id="codigo-aberto" tabindex="-1">Código Aberto <a class="header-anchor" href="#codigo-aberto" aria-label="Permalink to &quot;Código Aberto&quot;">​</a></h2><p>O Specialist Agent é publicado sob a <a href="https://github.com/HerbertJulio/specialist-agent/blob/main/LICENSE" target="_blank" rel="noreferrer">Licença MIT</a>. O código-fonte completo está disponível publicamente para revisão no <a href="https://github.com/HerbertJulio/specialist-agent" target="_blank" rel="noreferrer">GitHub</a>.</p><h2 id="privacidade-de-menores" tabindex="-1">Privacidade de Menores <a class="header-anchor" href="#privacidade-de-menores" aria-label="Permalink to &quot;Privacidade de Menores&quot;">​</a></h2><p>Esta ferramenta e site são destinados a desenvolvedores de software e não são direcionados a menores de 13 anos.</p><h2 id="alteracoes-nesta-politica" tabindex="-1">Alterações nesta Política <a class="header-anchor" href="#alteracoes-nesta-politica" aria-label="Permalink to &quot;Alterações nesta Política&quot;">​</a></h2><p>Podemos atualizar esta Política de Privacidade periodicamente. As alterações serão refletidas nesta página com a data de &quot;Última atualização&quot; atualizada. Para mudanças significativas, um aviso poderá ser publicado no repositório.</p><h2 id="contato" tabindex="-1">Contato <a class="header-anchor" href="#contato" aria-label="Permalink to &quot;Contato&quot;">​</a></h2><p>Se você tiver dúvidas sobre esta Política de Privacidade, abra uma issue no <a href="https://github.com/HerbertJulio/specialist-agent/issues" target="_blank" rel="noreferrer">GitHub</a> ou entre em contato com o mantenedor através do seu <a href="https://github.com/HerbertJulio" target="_blank" rel="noreferrer">perfil no GitHub</a>.</p>',30)])])}const h=a(t,[["render",s]]);export{m as __pageData,h as default};
